import os
import base64

# A simple "Image not found" placeholder as a base64-encoded PNG
IMAGE_DATA = """

"""

# Create directory if it doesn't exist
img_dir = os.path.join("app", "static", "img")
os.makedirs(img_dir, exist_ok=True)

# Save the image
img_path = os.path.join(img_dir, "image-not-found.png")
with open(img_path, "wb") as f:
    # Remove whitespace and newlines from the base64 string
    img_data = IMAGE_DATA.strip()
    f.write(base64.b64decode(img_data))

print(f"Created fallback image at {img_path}")
